const { createHmac } = require('crypto');
const secret = $env.N8N_WEBHOOK_SECRET;
const rawBody = JSON.stringify($json);
const ts = $headers['x-lwl-ts'];
const sig = $headers['x-lwl-sig'];
if (!ts || !sig) { throw new Error('unauthorized'); }
const skew = Math.abs(Math.floor(Date.now()/1000) - Number(ts));
if (skew > 300) { throw new Error('stale'); }
const expected = createHmac('sha256', secret).update(`${ts}.${rawBody}`).digest('hex');
if (expected !== sig) { throw new Error('bad_signature'); }
return $input.all();
